import{_ as s,c as a,o as n,aj as e}from"./chunks/framework.CynFBi0q.js";const b=JSON.parse('{"title":"第7章 产品需求文档（PRD）撰写","description":"","frontmatter":{},"headers":[],"relativePath":"handbook/ai-product/chapter_7.md","filePath":"handbook/ai-product/chapter_7.md","lastUpdated":1782008855000}'),d={name:"handbook/ai-product/chapter_7.md"};function p(r,t,l,i,o,h){return n(),a("div",null,[...t[0]||(t[0]=[e(`<h1 id="第7章-产品需求文档-prd-撰写" tabindex="-1">第7章 产品需求文档（PRD）撰写 <a class="header-anchor" href="#第7章-产品需求文档-prd-撰写" aria-label="Permalink to “第7章 产品需求文档（PRD）撰写”">​</a></h1><p>PRD是产品经理最重要的输出物之一。一份好的PRD能让开发减少80%的疑问，一份差的PRD能让开发骂你三个月。</p><p>我是怕浪猫，这一章不讲PRD的格式模板（网上一搜一大把），只讲怎么写出一份&quot;开发看了不骂人&quot;的PRD。</p><h2 id="_7-1-初识需求文档" tabindex="-1">7.1 初识需求文档 <a class="header-anchor" href="#_7-1-初识需求文档" aria-label="Permalink to “7.1 初识需求文档”">​</a></h2><h3 id="_7-1-1-prd-的作用与受众" tabindex="-1">7.1.1 PRD 的作用与受众 <a class="header-anchor" href="#_7-1-1-prd-的作用与受众" aria-label="Permalink to “7.1.1 PRD 的作用与受众”">​</a></h3><p>PRD的全称是Product Requirement Document，产品需求文档。</p><p><strong>PRD的核心作用</strong></p><p>第一，对齐认知。产品、设计、研发、测试对同一个功能的理解必须一致。PRD是&quot;共同语言&quot;。</p><p>第二，减少沟通成本。好PRD能让开发&quot;自己看懂&quot;，而不是每次都要过来问。</p><p>第三，留下决策记录。为什么要做这个功能？设计的时候考虑了哪些场景？PRD回答了这些问题，后续迭代时才能知道当初为什么这么设计。</p><p><strong>PRD的受众</strong></p><table tabindex="0"><thead><tr><th>受众</th><th>关注点</th><th>PRD要怎么写</th></tr></thead><tbody><tr><td>开发</td><td>怎么实现</td><td>逻辑清晰、边界明确、数据定义完整</td></tr><tr><td>设计</td><td>怎么设计</td><td>交互逻辑、状态定义、边界处理</td></tr><tr><td>测试</td><td>怎么测试</td><td>异常情况、边界条件、验收标准</td></tr><tr><td>老板</td><td>做什么、为什么</td><td>背景、目标、优先级</td></tr></tbody></table><p>一份PRD要同时满足四个受众的需求，所以需要&quot;分层写作&quot;——背景和目标写在前，设计和逻辑写在中间，细节和边界写在后。</p><h3 id="_7-1-2-prd-的基本结构" tabindex="-1">7.1.2 PRD 的基本结构 <a class="header-anchor" href="#_7-1-2-prd-的基本结构" aria-label="Permalink to “7.1.2 PRD 的基本结构”">​</a></h3><p>一份完整的PRD包含以下部分：</p><p><strong>第一部分：需求背景与目标（给老板和PM自己看）</strong></p><ul><li>为什么做这个需求？</li><li>希望达到什么目标？</li><li>优先级和排期如何？</li></ul><p><strong>第二部分：功能范围与用户故事（给所有人看）</strong></p><ul><li>这个功能包含哪些内容？</li><li>用户在什么场景下用这个功能？</li><li>用例（Use Case）拆解</li></ul><p><strong>第三部分：详细设计（给开发、设计、测试看）</strong></p><ul><li>页面原型（Axure链接或截图）</li><li>交互逻辑（点击后发生什么？）</li><li>数据定义（字段名、类型、取值范围）</li><li>异常流程（网络断了怎么办？数据为空怎么办？）</li></ul><p><strong>第四部分：非功能需求（给开发看）</strong></p><ul><li>性能要求（加载时间、并发量）</li><li>兼容性要求（支持哪些浏览器/系统版本）</li><li>安全要求（数据加密、权限控制）</li></ul><p><strong>第五部分：验收标准（给测试看）</strong></p><ul><li>每个功能点怎么测试？</li><li>验收通过的标准是什么？</li></ul><h3 id="_7-1-3-prd-与其他产品文档的关系-brd-mrd" tabindex="-1">7.1.3 PRD 与其他产品文档的关系（BRD/MRD） <a class="header-anchor" href="#_7-1-3-prd-与其他产品文档的关系-brd-mrd" aria-label="Permalink to “7.1.3 PRD 与其他产品文档的关系（BRD/MRD）”">​</a></h3><p>产品经理要写的文档不止PRD。按产品周期，文档体系是这样的：</p><table tabindex="0"><thead><tr><th>文档</th><th>全称</th><th>阶段</th><th>受众</th><th>核心内容</th></tr></thead><tbody><tr><td>BRD</td><td>Business Requirements Document</td><td>立项前</td><td>老板、投资人</td><td>商业价值、市场规模、ROI</td></tr><tr><td>MRD</td><td>Market Requirements Document</td><td>立项后</td><td>产品、市场、运营</td><td>市场需求、用户画像、竞品分析</td></tr><tr><td>PRD</td><td>Product Requirements Document</td><td>开发中</td><td>开发、设计、测试</td><td>功能需求、交互逻辑、数据定义</td></tr><tr><td>FSD</td><td>Functional Specification Document</td><td>开发后</td><td>开发、测试</td><td>功能规格、接口定义（技术向）</td></tr></tbody></table><p>BRD讲&quot;为什么做这个项目&quot;，MRD讲&quot;市场需要什么&quot;，PRD讲&quot;产品要做什么&quot;。分工明确，不要混在一起。</p><h2 id="_7-2-撰写产品需求文档" tabindex="-1">7.2 撰写产品需求文档 <a class="header-anchor" href="#_7-2-撰写产品需求文档" aria-label="Permalink to “7.2 撰写产品需求文档”">​</a></h2><h3 id="_7-2-1-需求背景与目标描述" tabindex="-1">7.2.1 需求背景与目标描述 <a class="header-anchor" href="#_7-2-1-需求背景与目标描述" aria-label="Permalink to “7.2.1 需求背景与目标描述”">​</a></h3><p><strong>需求背景怎么写</strong></p><p>好的背景描述 = 痛点 + 数据 + 目标</p><p>举例：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>【需求背景】</span></span>
<span class="line"><span>当前用户在搜索商品时，搜索结果页只按&quot;综合&quot;排序，用户无法按价格、销量等维度筛选。</span></span>
<span class="line"><span>数据表明：搜索结果页的跳出率高达42%，用户反馈中&quot;找不到想要的商品&quot;占比31%。</span></span>
<span class="line"><span>【需求目标】</span></span>
<span class="line"><span>上线搜索筛选功能，预期降低搜索结果页跳出率至30%以下。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>不好的背景描述：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>【需求背景】</span></span>
<span class="line"><span>用户需要搜索筛选功能。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>区别很明显：好的背景有数据支撑，有目标定义；不好的背景只有一句空洞的描述。</p><p><strong>需求目标怎么写</strong></p><p>目标要可衡量。不能说&quot;提升用户体验&quot;，要说&quot;搜索结果页跳出率从42%降低到30%以下&quot;。</p><p>好的目标公式：动词 + 指标 + 数值 + 时间</p><p>举例：</p><ul><li>提升搜索转化率 从18% 到 22% 在Q3前</li><li>降低下单流程流失率 从35% 到 25% 在V2.0上线后</li><li>提升新用户次日留存 从32% 到 38% 在Q4前</li></ul><h3 id="_7-2-2-功能需求详细说明" tabindex="-1">7.2.2 功能需求详细说明 <a class="header-anchor" href="#_7-2-2-功能需求详细说明" aria-label="Permalink to “7.2.2 功能需求详细说明”">​</a></h3><p>功能需求是PRD的核心。怎么写才能没有歧义？</p><p><strong>方法一：用用户故事（User Story）描述功能</strong></p><p>用户故事格式：作为一个[用户角色]，我希望[做什么]，以便于[达到什么目的]。</p><p>举例：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>作为一个搜索用户，</span></span>
<span class="line"><span>我希望在搜索结果页能按价格排序，</span></span>
<span class="line"><span>以便于快速找到符合预算的商品。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>用户故事的好处：把功能&quot;还原到场景&quot;中，避免只写功能不看场景。</p><p><strong>方法二：用用例（Use Case）描述交互</strong></p><p>用例格式：</p><ul><li>参与者：谁在用这个功能</li><li>前置条件：用户进入这个功能前是什么状态</li><li>主流程：用户做了什么，系统响应了什么</li><li>异常流程：如果出错了怎么办</li></ul><p>举例：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>【用例：搜索筛选】</span></span>
<span class="line"><span>- 参与者：已登录用户</span></span>
<span class="line"><span>- 前置条件：用户已进入搜索结果页</span></span>
<span class="line"><span>- 主流程：</span></span>
<span class="line"><span>  1. 用户点击&quot;筛选&quot;按钮</span></span>
<span class="line"><span>  2. 系统弹出筛选面板</span></span>
<span class="line"><span>  3. 用户选择&quot;价格：100-500元&quot;</span></span>
<span class="line"><span>  4. 用户点击&quot;确定&quot;</span></span>
<span class="line"><span>  5. 系统刷新搜索结果，只显示价格100-500元的商品</span></span>
<span class="line"><span>- 异常流程：</span></span>
<span class="line"><span>  - 用户未选择任何条件直接点击确定：关闭面板，不刷新结果</span></span>
<span class="line"><span>  - 网络异常：提示&quot;网络异常，请重试&quot;</span></span>
<span class="line"><span>  - 无符合条件的商品：展示&quot;暂无符合条件的商品&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p><strong>方法三：用表格描述数据字段</strong></p><p>对于涉及数据展示的功能，用表格描述字段最清晰：</p><table tabindex="0"><thead><tr><th>字段名</th><th>数据类型</th><th>说明</th><th>示例</th></tr></thead><tbody><tr><td>商品ID</td><td>Long</td><td>唯一标识</td><td>123456789</td></tr><tr><td>商品名称</td><td>String</td><td>最多30字</td><td>苹果手机壳</td></tr><tr><td>商品价格</td><td>Decimal</td><td>单位：元，保留两位小数</td><td>99.00</td></tr><tr><td>商品销量</td><td>Integer</td><td>累计销量</td><td>1024</td></tr><tr><td>商品图片</td><td>String</td><td>图片URL</td><td>https://...</td></tr></tbody></table><h3 id="_7-2-3-非功能需求-性能-安全-兼容性" tabindex="-1">7.2.3 非功能需求（性能/安全/兼容性） <a class="header-anchor" href="#_7-2-3-非功能需求-性能-安全-兼容性" aria-label="Permalink to “7.2.3 非功能需求（性能/安全/兼容性）”">​</a></h3><p>非功能需求经常被忽视，但恰恰是上线的&quot;隐形杀手&quot;。</p><p><strong>性能需求</strong></p><table tabindex="0"><thead><tr><th>场景</th><th>指标</th><th>目标值</th></tr></thead><tbody><tr><td>页面加载</td><td>首屏加载时间</td><td>&lt; 1.5秒</td></tr><tr><td>搜索响应</td><td>搜索结果返回时间</td><td>&lt; 500ms</td></tr><tr><td>并发</td><td>同时在线用户数</td><td>支持10万+</td></tr><tr><td>接口</td><td>API响应时间</td><td>&lt; 200ms（P95）</td></tr></tbody></table><p><strong>安全需求</strong></p><ul><li>用户密码必须加密存储（不可逆加密）</li><li>敏感数据（手机号、身份证）展示时必须脱敏</li><li>所有接口必须有鉴权机制</li><li>防止SQL注入、XSS等常见攻击</li></ul><p><strong>兼容性需求</strong></p><table tabindex="0"><thead><tr><th>平台</th><th>最低版本要求</th></tr></thead><tbody><tr><td>iOS</td><td>iOS 13.0及以上</td></tr><tr><td>Android</td><td>Android 8.0及以上</td></tr><tr><td>Web</td><td>Chrome 80+、Safari 14+</td></tr><tr><td>微信小程序</td><td>基础库 2.0+</td></tr></tbody></table><h3 id="_7-2-4-交互说明与异常流程处理" tabindex="-1">7.2.4 交互说明与异常流程处理 <a class="header-anchor" href="#_7-2-4-交互说明与异常流程处理" aria-label="Permalink to “7.2.4 交互说明与异常流程处理”">​</a></h3><p>异常流程是PRD里最容易遗漏的部分，但恰恰是最能体现产品经理专业度的部分。</p><p><strong>常见异常场景与处理方式</strong></p><table tabindex="0"><thead><tr><th>异常场景</th><th>处理方式</th></tr></thead><tbody><tr><td>网络断开</td><td>提示&quot;网络异常，请检查网络连接&quot;，并提供重试按钮</td></tr><tr><td>接口超时（&gt;5秒）</td><td>显示loading状态，超时后提示&quot;加载超时，请重试&quot;</td></tr><tr><td>数据为空</td><td>显示空状态页面，引导用户进行下一步操作</td></tr><tr><td>服务器错误（5xx）</td><td>显示&quot;系统繁忙，请稍后再试&quot;，并记录错误日志</td></tr><tr><td>无权限访问</td><td>显示&quot;暂无权限&quot;，并提供申请权限的入口</td></tr><tr><td>版本过低</td><td>强制更新提示，引导用户去应用商店更新</td></tr></tbody></table><p><strong>交互状态说明</strong></p><p>一个完整的PRD，应该覆盖一个功能的全部状态：</p><table tabindex="0"><thead><tr><th>状态</th><th>说明</th><th>视觉表现</th></tr></thead><tbody><tr><td>初始状态</td><td>用户第一次进入时的状态</td><td>引导提示、空状态</td></tr><tr><td>加载状态</td><td>数据加载中的状态</td><td>loading动画、骨架屏</td></tr><tr><td>空状态</td><td>没有数据时的状态</td><td>空状态插画+引导文案</td></tr><tr><td>正常状态</td><td>有数据时的正常展示</td><td>完整内容展示</td></tr><tr><td>错误状态</td><td>出现异常时的状态</td><td>错误提示+重试入口</td></tr><tr><td>操作反馈状态</td><td>用户操作后的反馈</td><td>Toast提示、弹窗确认</td></tr></tbody></table><h3 id="_7-2-5-数据埋点与验收标准" tabindex="-1">7.2.5 数据埋点与验收标准 <a class="header-anchor" href="#_7-2-5-数据埋点与验收标准" aria-label="Permalink to “7.2.5 数据埋点与验收标准”">​</a></h3><p><strong>数据埋点</strong></p><p>每一个功能上线，都要能回答&quot;这个功能用得怎么样&quot;。埋点设计就是要回答这个问题。</p><p>埋点设计表：</p><table tabindex="0"><thead><tr><th>事件名</th><th>触发时机</th><th>上报参数</th><th>说明</th></tr></thead><tbody><tr><td>search_filter_click</td><td>用户点击筛选按钮</td><td>user_id, search_keyword</td><td>统计筛选功能使用率</td></tr><tr><td>search_filter_apply</td><td>用户点击确定应用筛选</td><td>user_id, filter_conditions</td><td>统计筛选条件分布</td></tr><tr><td>search_result_impression</td><td>搜索结果曝光</td><td>user_id, result_list</td><td>统计搜索结果点击率</td></tr></tbody></table><p><strong>验收标准</strong></p><p>验收标准要&quot;可测试&quot;。不能说&quot;搜索功能正常&quot;，要说&quot;输入关键词后1秒内返回搜索结果，结果列表正确展示商品名称、价格、图片&quot;。</p><p>好的验收标准格式：Given（前置条件）When（操作） Then（预期结果）</p><p>举例：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>【验收标准：搜索筛选功能】</span></span>
<span class="line"><span>Given 用户已进入搜索结果页</span></span>
<span class="line"><span>When 用户点击&quot;筛选&quot;按钮</span></span>
<span class="line"><span>Then 弹出筛选面板，包含&quot;价格区间&quot;、&quot;商品分类&quot;、&quot;品牌&quot;三个筛选项</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Given 筛选面板已弹出</span></span>
<span class="line"><span>When 用户选择&quot;价格：100-500元&quot;并点击&quot;确定&quot;</span></span>
<span class="line"><span>Then 搜索结果刷新，只显示价格在100-500元之间的商品</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Given 筛选面板已弹出</span></span>
<span class="line"><span>When 用户未选择任何条件直接点击&quot;确定&quot;</span></span>
<span class="line"><span>Then 关闭筛选面板，搜索结果不刷新</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><blockquote><p>PRD写得好不好，看三个维度：逻辑是否闭环（主流程+异常流程全覆盖）、细节是否到位（数据字段+交互状态+边界条件）、验收是否可测（验收标准清晰可执行）。三个维度都达标，才是一份合格的PRD。</p></blockquote><hr><p>本章小结：PRD是产品经理最重要的输出物。背景要有数据支撑，功能要有场景还原，异常要全部穷举，验收要可测试可执行。记住：PRD的质量，决定了开发实现的质量。</p><p>觉得有用？收藏起来，下次写PRD直接照抄模板。</p><p>你见过最离谱的PRD是什么样的？评论区说说。</p><p>关注怕浪猫，下期我们讲&quot;从0到1全流程产品设计&quot;——从点子到产品，怕浪猫拆解这个过程中的每一个关键决策。</p><p>系列进度 7/16</p><p><strong>下章预告：</strong> 第8章，怕浪猫带你走一遍&quot;从点子到产品&quot;的全流程。不是讲理论，而是用一个真实的案例——如何从&quot;用户说想要更快的马&quot;到做出一个改变行业的产品。全流程串通，一次性讲透。</p>`,91)])])}const c=s(d,[["render",p]]);export{b as __pageData,c as default};
